import React from "react";
import { useQuery } from "@tanstack/react-query";
import Loading from "../Loading/Loading.jsx";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/navigation";
import "swiper/css/pagination";
import "./ProductsDetails.css";
import {
  Autoplay,
  EffectCoverflow,
  Navigation,
  Pagination,
} from "swiper/modules";
import { useParams } from "react-router-dom";
import { useEffect } from "react";

function parseNestedJson(jsonString) {
  try {
    const parsedObject = JSON.parse(jsonString);
    for (const key in parsedObject) {
      if (typeof parsedObject[key] === "string") {
        try {
          parsedObject[key] = JSON.parse(parsedObject[key]);
        } catch {
          // Keep the value as a string if parsing fails
        }
      }
    }
    return parsedObject;
  } catch {
    return null;
  }
}

function ProductsDetails() {
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  const { data, isLoading, isSuccess, error } = useQuery({
    queryKey: ["details"],
    queryFn: () =>
      fetch("http://127.0.0.1:8000/api/ProductDetails/1").then((res) =>
        res.json()
      ),
  });

  const { ProductId } = useParams();

  if (isLoading) {
    // Show a full-page loader during data fetch
    return <Loading />;
  }

  if (error) {
    return <div>Error loading product details</div>;
  }

  return (
    isSuccess && (
      <>
        <header>
          {/* Render your Navbar/Header */}
          <h1>Header</h1>
        </header>
        <main className="hugy-body">
          <div
            className="border-container"
            data-aos="fade-up"
            data-aos-duration="1000"
          >
            <h1 className="gg">
              {data[ProductId]?.product_name || "Product Details"}
            </h1>
            <Swiper
              className="pd-swiper"
              effect={"coverflow"}
              grabCursor={true}
              centeredSlides={true}
              slidesPerView={"auto"}
              coverflowEffect={{
                rotate: 50,
                stretch: 0,
                depth: 100,
                modifier: 1,
                slideShadows: false,
              }}
              navigation={true}
              autoplay={{
                delay: 3000,
              }}
              rewind={true}
              spaceBetween={10}
              pagination={{
                clickable: true,
                type: "bullets",
              }}
              modules={[EffectCoverflow, Pagination, Navigation, Autoplay]}
            >
              {data.map((item, index) => {
                const parsedImages = parseNestedJson(item.product_images).images;
                return parsedImages.slice(1).map((image, imgIndex) => (
                  <SwiperSlide
                    key={`${index}-${imgIndex}`}
                    className="pd-swiper-slide"
                  >
                    <img src={image} alt={`Slide ${imgIndex + 1}`} />
                  </SwiperSlide>
                ));
              })}
            </Swiper>
          </div>
        </main>
        <footer>
          {/* Render your Footer */}
          <h1>Footer</h1>
        </footer>
      </>
    )
  );
}

export default ProductsDetails;
